const showStatusHTML = (status) => {
  console.log("status", status);
  switch (status) {
    case "Draft":
      this.display(["draft_status"]);
      break;
    case "Created":
      this.display(["created_status"]);
      break;
    case "Completed":
      this.display(["completed_status"]);
      break;
    case "Cancelled":
      this.display(["cancel_status"]);
      break;
    default:
      break;
  }
};

const disabledField = async (status, pickingStatus) => {
  if (status === "Completed") {
    this.disabled(
      [
        "gd_status",
        "so_id",
        "so_no",
        "fake_so_id",
        "gd_billing_name",
        "gd_billing_cp",
        "gd_billing_address",
        "gd_shipping_address",
        "delivery_no",
        "gd_ref_doc",
        "customer_name",
        "gd_contact_name",
        "contact_number",
        "email_address",
        "document_description",
        "plant_id",
        "organization_id",
        "gd_delivery_method",
        "delivery_date",
        "driver_name",
        "driver_contact_no",
        "validity_of_collection",
        "sp_vehicle_no",
        "pickup_date",
        "courier_company",
        "shipping_date",
        "freight_charges",
        "tracking_number",
        "est_arrival_date",
        "driver_cost",
        "est_delivery_date",
        "shipping_company",
        "shipping_method",
        "order_remark",
        "billing_address_line_1",
        "billing_address_line_2",
        "billing_address_line_3",
        "billing_address_line_4",
        "billing_address_city",
        "billing_address_state",
        "billing_address_country",
        "billing_postal_code",
        "shipping_address_line_1",
        "shipping_address_line_2",
        "shipping_address_line_3",
        "shipping_address_line_4",
        "shipping_address_city",
        "shipping_address_state",
        "shipping_address_country",
        "shipping_postal_code",
        "gd_item_balance.table_item_balance",
        "select_vehicle_id",
        "select_driver_id",
        "order_tnc",
        "order_payment_details",
        "order_delivery_term",
        "order_remark",
        "order_remark2",
        "order_remark3",
        "order_remark4",
        "order_remark5",
      ],
      true,
    );

    // Disable table rows
    await disableTableRows();

    // Hide buttons and links
    this.hide([
      "link_billing_address",
      "link_shipping_address",
      "button_save_as_draft",
      "button_save_as_created",
      "button_save_as_completed",
    ]);
  } else {
    if (status === "Created") {
      this.hide(["button_save_as_draft"]);

      if (pickingStatus === "In Progress" || pickingStatus === "Completed") {
        this.hide(["button_save_as_created"]);
      }

      this.disabled(["plant_id"], true);
    }
    this.disabled(
      [
        "gd_ref_doc",
        "gd_delivery_method",
        "document_description",
        "gd_area_id",
        "sales_person",
        "order_tnc",
        "order_payment_details",
        "order_delivery_term",
        "order_remark",
        "order_remark2",
        "order_remark3",
        "order_remark4",
        "order_remark5",
        "select_vehicle_id",
        "select_driver_id",
      ],
      false,
    );
  }
};

const disableTableRows = async () => {
  return new Promise((resolve) => {
    setTimeout(async () => {
      try {
        const data = await this.getValues();
        const rows = data.table_gd || [];

        rows.forEach((row, index) => {
          const fieldNames = Object.keys(row).filter(
            (key) => key !== "gd_delivery_qty",
          );

          const fieldsToDisable = fieldNames.map(
            (field) => `table_gd.${index}.${field}`,
          );

          this.disabled(fieldsToDisable, true);
        });
        resolve();
      } catch (error) {
        console.error("Error disabling table rows:", error);
        resolve();
      }
    }, 1000);
  });
};

const displayDeliveryMethod = async () => {
  const deliveryMethodName = this.getValue("gd_delivery_method");
  console.log("deliveryMethodName", deliveryMethodName);

  if (
    deliveryMethodName &&
    typeof deliveryMethodName === "string" &&
    deliveryMethodName.trim() !== ""
  ) {
    this.setData({ delivery_method_text: deliveryMethodName });

    const visibilityMap = {
      "Self Pickup": "self_pickup",
      "Courier Service": "courier_service",
      "Company Truck": "company_truck",
      "Shipping Service": "shipping_service",
