      select_driver_id,
      gd_driver_contact,
      gd_driver_ic,
      vess_car_model,
      vess_chassis,
      vess_color,
    } = data;

    // Prepare goods delivery object
    const gd = {
      gd_status: targetStatus,
      picking_status: isGDPP ? "Completed" : picking_status,
      credit_limit_status: "Overridden",
      so_id,
