(async () => {
  const rowIndex = arguments[0].rowIndex;
  const weightConversion = arguments[0].value;

  // User manually edited the per-unit weight (weight_conversion). Recompute the
  // line net weight from the current so_quantity: net_weight = gd_quantity *
  // weight_conversion.
  if (
    weightConversion !== undefined &&
    weightConversion !== null &&
    weightConversion !== ""
  ) {
    const gdQuantity = this.getValue(`table_gd.${rowIndex}.gd_qty`) || 0;
    const netWeight =
      Math.round(Number(gdQuantity) * Number(weightConversion) * 1000) / 1000;
    this.setData({ [`table_gd.${rowIndex}.net_weight`]: netWeight });
  }
})();

